package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP07FiltrarPedidosTodosPlaywrightTest extends BaseTestPlaywright {    @Test    void administradorFiltraPedidosDelDiaPorEstadoTodos() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("admin");        page.locator("input[name='password']").fill("admin");        page.locator("button[type='submit']").click();        page.waitForTimeout(2000);        assertTrue(                page.content().contains("Panel Administrador"),                "No se visualiza el Panel Administrador."        );        page.locator("select[name='status']").selectOption("");        page.locator("button.filter-submit").click();        page.waitForTimeout(2000);        assertTrue(                page.content().contains("Estadísticas")                        || page.content().contains("Total Pedidos Completados")                        || page.content().contains("Total Ganancias"),                "No se visualizan las estadísticas del día después de filtrar."        );        assertTrue(                page.content().contains("ID_Mozo")                        && page.content().contains("Estado_pedido")                        && page.content().contains("Ver detalle"),                "No se visualiza la tabla de pedidos después de filtrar por estado Todos."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get("evidencias/HP07-filtro-estado-todos.png"))                        .setFullPage(true)        );    }}